const entrada = items[0].json;

const termosSql_diretos = (entrada.Itens_diretos || [])
  .map(t => `'${t}'`)
  .join(', ');

const termosSql_nao_listados = (entrada.itens_nao_listados || [])
  .map(t => `'${t}'`)
  .join(', ');

const output = [];

if (termosSql_diretos) {
  output.push({ json: { termosSql_diretos } });
}
if (termosSql_nao_listados) {
  output.push({ json: { termosSql_nao_listados } });
}

return output;

// Coleta todos os resultados em um único array
const produtos = $input.all().map(item => item.json);

return [
  {
    json: {
      produtos // array com todos os produtos, do jeito que veio
    }
  }
];

const termosString = $json.termosSql_nao_listados; // ou items[0].json.termosSql_nao_encontrados

// Remove aspas simples iniciais/finais e divide nos termos
const termosArray = termosString
  .split(", '")            // divide pelos separadores
  .map(t => t.replace(/^'|'$/g, '').trim()); // remove aspas simples sobrando

return termosArray.map(termo => ({ json: { termo } }));

return items.map(item => {
  const termoOriginal = item.json.termo || item.json.descricao_produto || "";
  const termo = termoOriginal
    .normalize('NFD')                    // separa letras de acentos
    .replace(/[\u0300-\u036f]/g, '')     // remove os acentos
    .toLowerCase();

  const stopwords = [
    'de','da','do','a','o','e','para','com','em','as','os','na','no','por',
    'à','das','dos','um','uma','ao','nao'
  ];

  const palavras_chave = termo
    .replace(/[^\w\s/"]/g, '')
    .split(/[\s,;:-]+/)
    .filter(w => w.length > 1 && !stopwords.includes(w) && isNaN(Number(w)))
    .filter((w,i,arr) => arr.indexOf(w) === i);

  const tipos = [
    'peneira','balança','forma','molde','prensa','cilindro','copo','bandeja',
    'funil','ampola','proveta','soquete','conjunto','jogo','cone','talhadeira',
    'pipeta','marreta','papel filtro','paquimetro','termometro','fixador',
    'recipiente','aparelho','medidor','vane','extrator','repartidor','picnometro','brucutu','hilf'
  ];
  const tipo_principal = tipos.find(tp => termo.includes(tp)) || palavras_chave[0] || '';

  const formatos = ['cilindrico','quadrada','redonda','chata','circular','oval','retangular'];
  const materiais = [
    'aco inox','inox','aluminio','latao','ferro','vidro','plastico',
    'polipropileno','bronze','cobre','madeira','papel','acrilico','duraluminio',
    'acero','aco duro','aco'
  ];
  const formato  = formatos.find(f => termo.includes(f))  || '';
  const material = materiais.find(m => termo.includes(m)) || '';

  const matchDimensao = termo.match(/([0-9]+[,.]?[0-9]*)\s*[x×]\s*([0-9]+[,.]?[0-9]*)(\s*(cm|mm|"))?/);
  const dimensao = matchDimensao
    ? `${matchDimensao[1]}x${matchDimensao[2]}${matchDimensao[4] || ''}`
    : '';

  const matchVolume = termo.match(/([0-9]+[.,]?[0-9]*)\s*(l|ml|litros?|ampolas?|g|gr|kg|kgf)\b/);
  const volume = matchVolume ? `${matchVolume[1]} ${matchVolume[2]}` : '';

  const matchMalha =
        termo.match(/\bpeneir\w*\s*([0-9]+(?:\/[0-9]+)?)/) ||
        termo.match(/malha\s*([0-9]+(?:\/[0-9]+)?)/);
  const malha = matchMalha ? matchMalha[1] : '';

  let abertura = '';
  let unidade_abertura = '';
  const matchAberturaMm =
        termo.match(/\(\s*([0-9]+[.,]?[0-9]*)\s*(mm|µm|um|μm)\s*\)/) ||
        termo.match(/abertura\s*([0-9]+[.,]?[0-9]*)\s*(mm|µm|um|μm)/);
  if (matchAberturaMm) {
    abertura = matchAberturaMm[1];
    unidade_abertura = matchAberturaMm[2];
  } else {
    const matchAberturaPol =
          termo.match(/([0-9]+\/[0-9]+)\s*("|''|in|pol)/) ||
          termo.match(/abertura\s*([0-9]+\/[0-9]+)\s*("|''|in|pol)/);
    if (matchAberturaPol) {
      abertura = matchAberturaPol[1];
      unidade_abertura = 'pol';
    }
  }

  const matchUnidade = termo.match(/\b(kg|g|gr|mg|ml|l|un|pc|pct|caixa|ampolas?|psi|kn|n|mm|cm|m|bar|μm|um|pol|")\b/gi);
  const unidade = matchUnidade ? matchUnidade.map(u => u.trim()) : [];
  const unidade_str = unidade.length ? unidade.join('|') : '';

  const matchQtdLote = termo.match(/\b([0-9]{1,4})\s*[x×]\s*([0-9]{1,4})\b(?![a-zA-Z])/);
  const quantidade_lote = matchQtdLote ? `${matchQtdLote[1]}x${matchQtdLote[2]}` : '';

  const matchClasse = termo.match(/(classe\s*[a-z0-9]+|tipo\s*[a-z0-9]+)/);
  const classe_tipo = matchClasse ? matchClasse[0] : '';

  const extras = [];
  if (termo.includes('com tampa'))          extras.push('com tampa');
  if (termo.includes('escala'))             extras.push('escala');
  if (termo.includes('graduada'))           extras.push('graduada');
  if (termo.includes('nao nuclear'))        extras.push('não nuclear');
  if (termo.includes('nao nucleo'))         extras.push('não nuclear');
  if (termo.includes('para uso geral'))     extras.push('para uso geral');
  if (termo.includes('resolucao') || termo.includes('resolução')) extras.push('resolução');
  const extras_str = extras.join('|');

  const matchVoltagem = termo.match(/([0-9]{2,3})\s*v\b/);
  const voltagem = matchVoltagem ? `${matchVoltagem[1]}V` : '';

  const matchFrequencia = termo.match(/([0-9]{2,3})\s*hz\b/);
  const frequencia = matchFrequencia ? `${matchFrequencia[1]}Hz` : '';

  const score_palavras_sql = palavras_chave.reduce((sql, palavra) => {
    const safe = palavra.replace(/["']/g, '');
    return sql + `
      + (CASE WHEN unaccent(descricao_produto) ILIKE CONCAT('%', unaccent('${safe}'), '%') THEN 0.2 ELSE 0 END)
    `;
  }, '').trim();

  return {
    json: {
      termo: termoOriginal,
      tipo_principal,
      formato,
      material,
      dimensao,
      volume,
      malha,
      abertura,
      unidade_abertura,
      unidade,
      unidade_str,
      quantidade_lote,
      classe_tipo,
      extras,
      extras_str,
      voltagem,
      frequencia,
      palavras_chave,
      score_palavras_sql
    }
  };
});

function normalize(str){
  return (str||"")
    .normalize("NFD").replace(/[\u0300-\u036f]/g,"")
    .replace(/[^\w\s]/g,"").replace(/\s+/g," ")
    .toLowerCase().trim();
}

const stopwords = ["de","da","do","dos","das","a","o","e","em","para","com"];

function removeStopwords(str){
  return str.split(" ").filter(w=>!stopwords.includes(w)).join(" ");
}

const termos = [
  "ALMOFARIZ","BACIA","BANDEJA","BANHO MARIA","CAPSULA PORCELANA",
  "CASAGRANDE","CESTO","COPO BEKCER","COROA DIAMANTADA","DENSIDADE IN SITU",
  "DENSIMETRO","DISCO ESPAÇADOR","ESTUFA","MOLDE CBR","PRATO NEOPRENE",
  "PRENSA CBR","PRENSA CONCRETO","PRENSA MARSHALL","REGUA BISELADA",
  "SACO AREIA CALIBRADA","SOQUETE CBR","VICAT","SLUMP TEST","MOLDE 10x20",
  "CORPO DE PROVA 10X20","PROVETA","AREIA CALIBRADA","RELOGIO COMPARADOR",
  "EXTENSOMETRO","CONJUNTO DE CRAVAÇÃO","HILF","MOLDE AASHTO 6 POLEGADAS",
];

const raw_dicionario = {
  "prensas de concreto":"PRENSA CONCRETO",
  "prensa de concreto":"PRENSA CONCRETO",
  "prensas concreto":"PRENSA CONCRETO",
  "prensas cbr":"PRENSA CBR",
  "prensas marshall":"PRENSA MARSHALL",
  "Cilindro 10x20":"MOLDE 10x20",
  "cápsula de porcelana":"CAPSULA PORCELANA",
  "jogo de Slump":"SLUMP TEST",
  "conjunto slump test":"SLUMP TEST",
  "conjunto hilf":"CONJUNTO DE CRAVAÇÃO",
  "brucutu":"CONJUNTO DE CRAVAÇÃO",
  "cilindro proctor grande": "MOLDE AASHTO 6 POLEGADAS",
  "molde proctor grande": "MOLDE AASHTO 6 POLEGADAS",
};

const dicionario = {};
for (const k in raw_dicionario){
  dicionario[removeStopwords(normalize(k))] = raw_dicionario[k];
}

// -------------- AQUI É A MUDANÇA -----------------
let entrada = items[0].json.Item || "";   // vinha como query, agora é Item
// ------------------------------------------------

let partes = [];

if (typeof entrada === "string"){
  partes = [entrada.trim()];
}else if (Array.isArray(entrada)){
  partes = entrada.map(s=>String(s).trim()).filter(Boolean);
}

const Itens_diretos = [];
const itens_nao_listados = [];

for (const p of partes){
  const norm = removeStopwords(normalize(p));
  let termo = dicionario[norm];

  if (!termo){
    termo = termos.find(t=>removeStopwords(normalize(t)) === norm);
  }

  if (termo){
    if (!Itens_diretos.includes(termo)) Itens_diretos.push(termo);
  }else{
    itens_nao_listados.push(p);
  }
}

return [{
  json:{
    Itens_diretos,
    itens_nao_listados
  }
}];

const produtos = items[0].json.data || [];

// Encontra o maior score da lista
const maxScore = produtos.reduce((max, p) => Math.max(max, Number(p.score_total)), 0);

// Define um limiar como % do maior (por exemplo, 90%)
const threshold = maxScore * 0.7;

// Se quiser garantir que pelo menos um produto entra em topProdutos:
const topProdutos = produtos.filter(p => Number(p.score_total) >= threshold);
const outrosProdutos = produtos.filter(p => Number(p.score_total) < threshold);

return [
  {
    json: {
      topProdutos,
      outrosProdutos
    }
  }
];

